// Revisión técnica solar con cascada de proveedores.
// Orden: Gemini (Google AI) → GROQ → Mistral → Claude (Anthropic).
// Cada proveedor tiene tier gratuito; el primero disponible responde.
//
// Env opcionales:
//   GOOGLE_AI_KEY      (Gemini)   — https://aistudio.google.com
//   GROQ_API_KEY                  — https://console.groq.com
//   MISTRAL_API_KEY               — https://console.mistral.ai
//   ANTHROPIC_API_KEY  (Claude)   — fallback pago

const src = $input.first().json;
const body = src.body || src;
const context = (body.context || 'review').toString();
const payload = body.payload || {};

const system = 'Eres un ingeniero eléctrico especializado en sistemas solares fotovoltaicos en Colombia. Conoces RETIE, CREG 038/2014, CREG 174/2021 (AGPE), Ley 1715, estándares NEC/IEC. Analiza el dimensionamiento que te envía el cotizador y devuelve observaciones concretas, accionables y técnicas. Usa español neutro.';

const userPrompt = `Contexto: ${context}\n\nSistema a revisar (JSON):\n${JSON.stringify(payload, null, 2)}\n\nDevuelve SOLO JSON válido con esta forma exacta (sin markdown):\n{\n  \"summary\": string,\n  \"findings\": string[],\n  \"warnings\": string[],\n  \"suggestions\": string[]\n}\n\nReglas:\n- summary: 1-2 frases, lenguaje ejecutivo.\n- findings: 2-5 observaciones técnicas clave.\n- warnings: alertas críticas (voc fuera de rango, banco subdimensionado, excedentes fuera de AGPE, etc). Vacío si no hay.\n- suggestions: 2-4 acciones recomendadas específicas.\n- NO inventes valores. Trabaja solo con los datos del payload.`;

function extractJson(text) {
  const m = (text || '').match(/\{[\s\S]*\}/);
  if (!m) throw new Error('Sin JSON parseable');
  return JSON.parse(m[0]);
}

async function tryGemini() {
  const K = $env.GOOGLE_AI_KEY;
  if (!K) return null;
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${K}`,
    headers: { 'content-type': 'application/json' },
    body: {
      systemInstruction: { parts: [{ text: system }] },
      contents: [{ role: 'user', parts: [{ text: userPrompt }] }],
      generationConfig: { temperature: 0.2, maxOutputTokens: 1024, responseMimeType: 'application/json' },
    },
    json: true,
  });
  const text = r.candidates?.[0]?.content?.parts?.map(p => p.text || '').join('') || '';
  const parsed = extractJson(text);
  const u = r.usageMetadata || {};
  return { parsed, provider: 'gemini-2.0-flash', tokens: { in: u.promptTokenCount || 0, out: u.candidatesTokenCount || 0 } };
}

async function tryGroq() {
  const K = $env.GROQ_API_KEY;
  if (!K) return null;
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: { 'authorization': `Bearer ${K}`, 'content-type': 'application/json' },
    body: {
      model: 'llama-3.3-70b-versatile',
      messages: [{ role: 'system', content: system }, { role: 'user', content: userPrompt }],
      temperature: 0.2,
      max_tokens: 1024,
      response_format: { type: 'json_object' },
    },
    json: true,
  });
  const text = r.choices?.[0]?.message?.content || '';
  const parsed = extractJson(text);
  const u = r.usage || {};
  return { parsed, provider: 'groq-llama-3.3-70b', tokens: { in: u.prompt_tokens || 0, out: u.completion_tokens || 0 } };
}

async function tryMistral() {
  const K = $env.MISTRAL_API_KEY;
  if (!K) return null;
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.mistral.ai/v1/chat/completions',
    headers: { 'authorization': `Bearer ${K}`, 'content-type': 'application/json' },
    body: {
      model: 'mistral-large-latest',
      messages: [{ role: 'system', content: system }, { role: 'user', content: userPrompt }],
      temperature: 0.2,
      max_tokens: 1024,
      response_format: { type: 'json_object' },
    },
    json: true,
  });
  const text = r.choices?.[0]?.message?.content || '';
  const parsed = extractJson(text);
  const u = r.usage || {};
  return { parsed, provider: 'mistral-large', tokens: { in: u.prompt_tokens || 0, out: u.completion_tokens || 0 } };
}

async function tryClaude() {
  const K = $env.ANTHROPIC_API_KEY;
  if (!K) return null;
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: { 'x-api-key': K, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
    body: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 1024,
      system,
      messages: [{ role: 'user', content: userPrompt }],
    },
    json: true,
  });
  const text = (r.content || []).map(c => c.text || '').join('\n');
  const parsed = extractJson(text);
  const u = r.usage || {};
  return { parsed, provider: 'claude-haiku-4-5', tokens: { in: u.input_tokens || 0, out: u.output_tokens || 0 } };
}

const providers = [
  ['gemini', tryGemini],
  ['groq', tryGroq],
  ['mistral', tryMistral],
  ['claude', tryClaude],
];

const errors = [];
for (const [name, fn] of providers) {
  try {
    const result = await fn.call(this);
    if (!result) { errors.push(`${name}: no key`); continue; }
    const p = result.parsed;
    return [{ json: {
      summary: p.summary || '',
      findings: Array.isArray(p.findings) ? p.findings : [],
      warnings: Array.isArray(p.warnings) ? p.warnings : [],
      suggestions: Array.isArray(p.suggestions) ? p.suggestions : [],
      provider: result.provider,
      tokens: result.tokens,
      cascadeErrors: errors,
    } }];
  } catch (e) {
    errors.push(`${name}: ${e.message || e}`);
  }
}

throw new Error('Todos los proveedores IA fallaron: ' + errors.join(' | '));
